set check_function_bodies = off;
set client_min_messages = warning;



-- file: functions/_private/capture_closing_line.sql
-- Flags the closing line (latest pre-kickoff row per game+source) write-once.
-- Called at the start of _grade_games_by_ids; skips any (game, source) already flagged.
--
-- Capture only ever runs on the grade path, so it reaches a game exactly once -- at its
-- first grade -- and never revisits one already graded. That is what left 2025 flagged
-- 16/272 (#735): this function shipped with #177 on 2026-06-26, months after the season
-- finished grading, so 255 games were already past the only moment it could have fired.
-- Nothing here was wrong; the gap was closed by a one-off backfill calling this function
-- over those games. Any future mid-season change to the capture rule needs the same
-- treatment -- re-grading is not a path that re-captures.
create or replace function public._capture_closing_line(p_game_ids uuid[])
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  update public.game_lines gl set is_closing_line = true
  from (
    select distinct on (l.game_id, l.source) l.id
    from public.game_lines l
    join public.games g on g.id = l.game_id
    where l.game_id = any(p_game_ids)
      and l.fetched_at <= g.commence_time
      and not exists (
        select 1 from public.game_lines c
        where c.game_id = l.game_id and c.source = l.source and c.is_closing_line
      )
    order by l.game_id, l.source, l.fetched_at desc, l.id desc
  ) winner
  where gl.id = winner.id;
end;
$$;

-- file: functions/_private/grade_games_by_ids.sql
-- This is a new internal helper function. Note the leading underscore.
create or replace function public._grade_games_by_ids(p_game_ids uuid[])
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_missing_closing text;
begin
  -- Freeze imported seasons (ADR-0024): never (re)grade a game in a locked season.
  -- Strips locked-season games up front so closing-line capture and BOTH settlement
  -- passes below operate only on gradable games. This is the single choke point --
  -- grade_game / grade_week / grade_season and the grade cron all funnel through here,
  -- as will the #433 reconcile sweep -- so a locked (pre-2025 imported) season is inert
  -- to every grade path and its sheet-sourced settlements can never be re-derived.
  select coalesce(array_agg(g.id), '{}')
    into p_game_ids
  from public.games g
  join public.weeks w on w.id = g.week_id
  join public.seasons s on s.id = w.season_id
  where g.id = any(p_game_ids)
    and not s.grading_locked;

  if array_length(p_game_ids, 1) is null then
    return;
  end if;

  -- Capture the closing line for each game before grading (write-once).
  perform public._capture_closing_line(p_game_ids);

  -- Under House the closing line IS the graded line (ADR-0007), so refuse to grade a
  -- House row without one instead of silently substituting the pick-time line (#735).
  -- Runs AFTER capture above, so it can only fire when no pre-kickoff game_lines row
  -- ever existed to flag -- broken data, not a capture-timing artifact. It is the
  -- reason the House branch below reads cl.spread_* directly: grade_pick's margin
  -- comparisons are all false against a NULL spread, so it would fall through to
  -- 'loss' for EVERY pick on the game rather than failing. This predicate is the exact
  -- negation of that branch's `cl` lateral -- same effective-preset chain, same
  -- line_source, evaluated per pick row -- so the two can never disagree. Games with no
  -- picks are excluded: the missed-penalty pass below never reads a line.
  select string_agg(distinct m.game_id::text, ', ')
    into v_missing_closing
  from (
    select g.id as game_id
    from public.games g
    join public.picks p on p.game_id = g.id
    left join public.group_config cfg on cfg.group_id = p.group_id
    left join public.pick_settlement ps_prior
      on ps_prior.group_id = p.group_id
     and ps_prior.user_id  = p.user_id
     and ps_prior.game_id  = g.id
    left join lateral (
      select ps2.graded_preset
      from public.pick_settlement ps2
      where ps2.group_id = p.group_id
        and ps2.game_id  = g.id
      limit 1
    ) ps_cohort on true
    where g.id = any(p_game_ids)
      and coalesce(ps_prior.graded_preset, ps_cohort.graded_preset, cfg.grading_preset, 'gamer') = 'house'
      and not exists (
        select 1
        from public.game_lines gl
        where gl.game_id = g.id
          and gl.source  = coalesce(cfg.line_source, 'fanduel')
          and gl.is_closing_line
      )
  ) m;

  if v_missing_closing is not null then
    raise exception
      'grade: House preset requires a closing line but none exists for game(s) %; refusing to grade on the pick-time line (ADR-0007, #735)',
      v_missing_closing
      using errcode = 'P0001';
  end if;

  -- (1) Upsert settlements for users who DID make a pick on the given games.
  -- Effective preset = coalesce(this row's own prior, any cohort row already graded for
  -- this game, group config, 'gamer'). Frozen per game, first grade wins (ADR-0007
  -- 2026-07-15 amendment, #657): ps_prior alone only freezes a row that already exists,
  -- so a row born late into an already-graded game (added member, backfilled gap) fell
  -- through to today's group config instead of its game's frozen preset. ps_cohort closes
  -- that gap by checking ANY settlement already graded for this (group, game), not just
  -- this user's own.
  insert into public.pick_settlement (group_id, user_id, game_id, pick_id, points_delta, outcome, graded_at, graded_preset)
  select
    p.group_id,
    p.user_id,
    g.id,
    p.id,
    gp.points_delta,
    gp.outcome,
    now(),
    eff.preset
  from public.games g
  join public.picks p on p.game_id = g.id
  left join public.group_config cfg on cfg.group_id = p.group_id
  left join public.pick_settlement ps_prior
    on ps_prior.group_id = p.group_id
   and ps_prior.user_id  = p.user_id
   and ps_prior.game_id  = g.id
  left join lateral (
    select ps2.graded_preset
    from public.pick_settlement ps2
    where ps2.group_id = p.group_id
      and ps2.game_id  = g.id
    limit 1
  ) ps_cohort on true
  left join lateral (
    select gl.spread_team_id, gl.spread_value
    from public.game_lines gl
    where gl.game_id = g.id
      and gl.source  = coalesce(cfg.line_source, 'fanduel')
      and gl.is_closing_line
    limit 1
  ) cl on true
  cross join lateral (
    select coalesce(ps_prior.graded_preset, ps_cohort.graded_preset, cfg.grading_preset, 'gamer') as preset
  ) eff
  cross join lateral public.grade_pick(
    (g.final_scores->>'home')::int,
    (g.final_scores->>'away')::int,
    g.home_team_id,
    g.away_team_id,
    p.picked_team_id,
    -- House reads the closing line directly -- no coalesce to the pick-time line. The
    -- guard above has already proven cl is present for every House row here, and a
    -- fallback would be exactly the silent degradation #735 was filed for.
    case when eff.preset = 'house'
         then cl.spread_team_id
         else p.locked_spread_team_id end,
    case when eff.preset = 'house'
         then cl.spread_value
         else p.locked_spread_value end,
    p.weight::text
  ) as gp
  where g.id = any(p_game_ids)
  on conflict (group_id, user_id, game_id)
  do update set
    pick_id      = excluded.pick_id,
    points_delta = excluded.points_delta,
    outcome      = excluded.outcome,
    graded_at    = excluded.graded_at,
    graded_preset = excluded.graded_preset;

  -- (2) Upsert "missed" penalties for every ACTIVE league member who did NOT make a pick.
  -- Population is group membership, NOT global users.role (ADR-0024): the missed penalty is
  -- a league-participation rule, so a competing app-admin (users.role='admin') is penalized
  -- exactly like any other member -- the prior u.role='player' filter silently exempted the
  -- admin, which flipped the 2022 champion after the #430 re-grade. 'pending' invites are
  -- excluded. Admin app-access (is_admin(), settings/audit_log RLS) is unaffected by this.
  -- Line is irrelevant for missed picks; graded_preset is set for consistency.
  insert into public.pick_settlement (group_id, user_id, game_id, pick_id, points_delta, outcome, graded_at, graded_preset)
  select
    gm.group_id,
    u.id,
    g.id,
    null,
    public.resolve_missed_penalty_for_game(g.id),
    'missed'::public.pick_outcome,
    now(),
    coalesce(ps_prior.graded_preset, ps_cohort.graded_preset, cfg.grading_preset, 'gamer')
  from public.games g
  cross join public.group_memberships gm
  join public.users u on u.id = gm.user_id
  left join public.group_config cfg on cfg.group_id = gm.group_id
  left join public.pick_settlement ps_prior
    on ps_prior.group_id = gm.group_id
   and ps_prior.user_id  = u.id
   and ps_prior.game_id  = g.id
  left join lateral (
    select ps2.graded_preset
    from public.pick_settlement ps2
    where ps2.group_id = gm.group_id
      and ps2.game_id  = g.id
    limit 1
  ) ps_cohort on true
  where g.id = any(p_game_ids)
    and gm.status = 'active'
    and not exists (
      select 1
      from public.picks p
      where p.group_id = gm.group_id
        and p.game_id = g.id
        and p.user_id = u.id
    )
  on conflict (group_id, user_id, game_id)
  do update set
    -- Only update if the existing settlement is also for a missed pick.
    -- This prevents overwriting a real pick that was graded out of order.
    pick_id       = excluded.pick_id,
    points_delta  = excluded.points_delta,
    outcome       = excluded.outcome,
    graded_at     = excluded.graded_at,
    graded_preset = excluded.graded_preset
  where pick_settlement.pick_id is null;
end;
$$;
